// Turn the array of leads into individual items
const leads = items[0].json.leads || [];
return leads.map(lead => ({ json: lead }));

// Simple scoring model – tweak as needed
const item = items[0].json;
let score = 50; // base score

// Add points for company size
if (item.company && item.company.metrics && item.company.metrics.employees) {
  const emp = item.company.metrics.employees;
  if (emp > 1000) score += 20;
  else if (emp > 200) score += 10;
  else score += 5;
}

// Domain quality
if (item.email && item.email.endsWith('@gmail.com')) score -= 15;

// Industry match example
if (item.company && item.company.category && item.company.category.industry === 'Software') score += 10;

// Funding indicator
if (item.company && item.company.metrics && item.company.metrics.raised) score += 10;

return [{ json: { ...item, score } }];

// Assign minimal score when enrichment fails
const lead = items[0].json;
lead.score = 10;
return [{ json: lead }];
